import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { ReviewService, Review } from '../../services/review.service';
import { ReviewCardComponent } from '../../components/review-card/review-card.component';
import { NavbarComponent } from '../../components/navbar/navbar.component';

@Component({
  selector: 'app-feed',
  standalone: true,
  imports: [CommonModule, ReviewCardComponent, NavbarComponent],
  templateUrl: './feed.component.html',
  styleUrl: './feed.component.css'
})
export class FeedComponent implements OnInit {
  reviews: Review[] = [];
  loading = true;
  error: string | null = null;
  activeTab = 'global';

  constructor(
    private reviewService: ReviewService,
    private router: Router
  ) {}

  ngOnInit() {
    this.loadFeed();
  }

  loadFeed() {
    this.loading = true;
    this.error = null;

    const feedObservable = this.activeTab === 'global'
      ? this.reviewService.getGlobalFeed()
      : this.reviewService.getFriendsFeed();

    feedObservable.subscribe({
      next: (reviews) => {
        this.reviews = reviews;
        this.loading = false;
      },
      error: () => {
        this.error = 'Failed to load feed. Please try logging in again.';
        this.loading = false;
      }
    });
  }

  switchTab(tab: string) {
    this.activeTab = tab;
    this.loadFeed();
  }

  createReview() {
    this.router.navigate(['/create-review']);
  }
}
<div class="feed-container">
  <app-navbar></app-navbar>

  <div class="feed-content">
    <div class="tabs">
      <button
        class="tab-button"
        [class.active]="activeTab === 'global'"
        (click)="switchTab('global')"
      >
        🌍 Global Feed
      </button>
      <button
        class="tab-button"
        [class.active]="activeTab === 'friends'"
        (click)="switchTab('friends')"
      >
        👥 Friends Only
      </button>
    </div>

    <div *ngIf="loading" class="loading">Loading reviews...</div>

    <div *ngIf="!loading && reviews.length === 0" class="empty-state">
      <p>No reviews yet. Start following friends or check back later!</p>
    </div>

    <div *ngIf="!loading && reviews.length > 0" class="reviews-list">
      <app-review-card
        *ngFor="let review of reviews"
        [review]="review"
      ></app-review-card>
    </div>
  </div>
</div>
